/**
 * mesh-model-registry — per-model config for the SINGLE consolidated mesh
 * service (one Cloud Run service / one GPU slot, model loaded on demand).
 *
 * Today each model is its own `gnosis-openai-*` Cloud Run service baked with a
 * single knot; ~10 services fight over a 3-GPU quota → cold-start 503s + handoff
 * deadlocks. The consolidated mesh runs ONE service that loads the requested
 * model's knot on demand (fat-station restart, serialized by the pipeline mutex)
 * and rebuilds its tokenizer/chat-template per model from THIS registry.
 *
 * Each entry carries everything the openai-server + fat-station need to serve a
 * model — sourced from the live per-model service envs so behavior is identical.
 */

export interface MeshModelConfig {
  /** Canonical model id (what callers request, e.g. 'mistral-7b'). */
  id: string;
  /** Exact MODEL_NAME the served backend reports + admits. */
  modelName: string;
  /** Aliases that resolve to this model. */
  aliases: string[];
  /** Knot weights URL (R2; fat-station range-fetches + caches). */
  knotUrl: string;
  /** Tokenizer family for the openai-server (drives prompt rendering). */
  tokenizerFamily: 'llama' | 'qwen2' | 'hf-bpe-metaspace';
  /** Chat template id. `raw` = no wrapping (base/completion models). */
  chatTemplate:
    | 'llama2'
    | 'llama3'
    | 'qwen-chatml'
    | 'mistral-v3-instruct'
    | 'gemma'
    | 'gemma4'
    | 'zephyr'
    | 'raw';
  /** Optional HF tokenizer.json URL (hf-bpe-metaspace models). */
  tokenizerJsonUrl?: string;
  /** Optional tokenizer-bearing GGUF URL (knots without an embedded tokenizer,
   *  e.g. loki — fat-station reads tokenizer.ggml.* from it). Baked/cached local. */
  tokenizerGgufUrl?: string;
  /** Extra stop token ids (e.g. llama3 <|eot_id|>=128009 the GGUF eos misses). */
  stopTokens?: number[];
  /** Extra per-model child env. Used for model-specific kernel/admission knobs. */
  env?: Readonly<Record<string, string>>;
  /** GPU weight dtype + budget (f16 fits 7-8B on an L4). */
  fluxGpuWeightDtype?: 'f16' | 'f32';
  fluxGpuF16BudgetGb?: number;
}

export interface MeshServingResolution {
  requestedModel: string | undefined;
  requestedConfig: MeshModelConfig | null;
  config: MeshModelConfig | null;
  rewriteModel?: string;
  routedFrom?: string;
  reason?: string;
}

